const _subLogoLocks = new Set();

// Upload a sub's logo/avatar. Client-side type + 2 MB cap mirrors
// ProfileSheet.onPickLogo (crm-subs-tab.jsx:520-538); FileReader-to-base64
// is the exact same pattern uploadJobPhoto (below) already uses for
// crm-media-upload.
export async function uploadSubLogo(file, subId) {
  const CRM = window.CRM;
  if (!CRM || typeof CRM.__invokeFn !== 'function') return { ok: false, error: 'Supabase not loaded' };
  if (!subId || !file) return { ok: false, error: 'no sub/file' };
  if (!/^image\/(png|jpe?g|webp)$/.test(file.type || '')) return { ok: false, error: 'PNG, JPG, or WebP only' };
  if (file.size > 2 * 1024 * 1024) return { ok: false, error: 'Logo must be under 2 MB' };
  if (_subLogoLocks.has(subId)) return { ok: false, inFlight: true };
  _subLogoLocks.add(subId);
  try {
    let dataBase64;
    try {
      dataBase64 = await new Promise((resolve, reject) => {
        const r = new FileReader();
        r.onload = () => { const s = String(r.result || ''); resolve(s.slice(s.indexOf(',') + 1)); };
        r.onerror = () => reject(new Error('could not read file'));
        r.readAsDataURL(file);
      });
    } catch (e) {
      return { ok: false, error: (e && e.message) || 'could not read file' };
    }
    const { data, error } = await CRM.__invokeFn('sub-logo-upload', {
      body: { sub_id: subId, contentType: file.type, dataBase64 },
    });
    if (error) return { ok: false, error: await subFnErrorDetail(error) };
    if (data && data.error) return { ok: false, error: data.error };
    if (!data || !data.logo_url) return { ok: false, error: 'no logo url returned' };
    dispatchSubChanged();
    return { ok: true, url: data.logo_url };
  } catch (e) {
    return { ok: false, error: String((e && e.message) || e) };
  } finally {
    _subLogoLocks.delete(subId);
  }
}

// ── Sub job-offer lifecycle (Ionic Increment T2) ─────────────────────────
// Mirror of JobSheet + SubCard writes in crm-subs-tab.jsx (copyJobLink,
// EditField, PermitControl, withdraw, approvePayout). Money floor:
// approve-payout fires ONLY the existing gated fn behind an explicit
// confirm owned by the caller. installer_pay / payout_* are DOLLARS, never
// pass them to formatDue (cents). The cents boundary is sub_payouts
// amount_cents, written server-side.

export const PERMIT_FLAT_DEFAULT = 75;
export const OFFER_ACTIVE_STATUSES = ['offered', 'accepted', 'permit_submitted', 'install_submitted', 'pass_submitted'];
export const OFFER_PAYOUT_LOCKED_STATUSES = ['accepted', 'permit_submitted', 'install_submitted', 'pass_submitted', 'approved_paid'];
export const OFFER_TERMINAL_STATUSES = ['declined', 'withdrawn', 'expired'];

// Dollars display for payout fields. NEVER formatDue (that expects cents).
export function formatPayoutDollars(n) {
  if (n == null || n === '' || isNaN(Number(n))) return '$0';
  return '$' + Number(n).toLocaleString(undefined, { minimumFractionDigits: 0, maximumFractionDigits: 0 });
}

export function parsePayoutMoney(s) {
  const n = Number(String(s == null ? '' : s).replace(/[^0-9.]/g, ''));
  return isNaN(n) ? null : n;
}

// job_code is NOT in the view:'jobs' payload; derive like buildProfile.
export function offerJobCode(offerId) {
  if (!offerId) return '';
  return String(offerId).replace(/-/g, '').slice(0, 6).toUpperCase();
}

// Three-way permit mode <-> {permit_owner, permit_required}, mirror of
// permitModeOf in crm-subs-tab.jsx.
export function permitModeOf(owner, required) {
  if (required === false) return 'none';
  return owner === 'bpp' ? 'bpp' : 'sub';
}

export function permitTermsFromMode(mode, currentOwner) {
  if (mode === 'bpp') return { permit_owner: 'bpp', permit_required: true };
  if (mode === 'none') return { permit_owner: currentOwner === 'bpp' ? 'bpp' : 'sub', permit_required: false };
  return { permit_owner: 'sub', permit_required: true };
}

// Pick the one active (or most recent) offer for a contact from a jobs list.
// Prefer an active/non-terminal row; else the newest row for that contact.
export function pickContactJob(jobs, contactId) {
  if (!contactId || !Array.isArray(jobs)) return null;
  const forContact = jobs.filter(j => String(j.contact_id) === String(contactId));
  if (!forContact.length) return null;
  const active = forContact.find(j => OFFER_ACTIVE_STATUSES.includes(j.status) || j.status === 'approved_paid');
  return active || forContact[0] || null;
}

// Contact-scoped offer fetch. view:'jobs' ignores filter params server-side
// (always returns every offer); filter client-side like SubCard does.
export function useContactJobOffer(contactId) {
  const [job, setJob] = React.useState(undefined); // undefined=loading, null=none
  const [loading, setLoading] = React.useState(true);
  const [error, setError] = React.useState(null);
  const seqRef = React.useRef(0);

  const load = React.useCallback(() => {
    const seq = ++seqRef.current;
    if (!contactId) { setLoading(false); setJob(null); return; }
    if (!window.CRM || typeof window.CRM.__invokeFn !== 'function') {
      setLoading(false);
      setError('not connected');
      setJob(null);
      return;
    }
    setLoading(true);
    setError(null);
    window.CRM.__invokeFn('sub-admin-list', { body: { view: 'jobs', contact_id: contactId } })
      .then(({ data, error: err }) => {
        if (seq !== seqRef.current) return;
        setLoading(false);
        if (err) { setError(err.message || 'failed'); setJob(null); return; }
        const jobs = (data && data.jobs) || [];
        setJob(pickContactJob(jobs, contactId));
      })
      .catch(e => {
        if (seq !== seqRef.current) return;
        setLoading(false);
        setError(String((e && e.message) || e));
        setJob(null);
      });
  }, [contactId]);

  React.useEffect(() => {
    load();
    window.addEventListener('crm-sub-changed', load);
    return () => {
      seqRef.current++;
      window.removeEventListener('crm-sub-changed', load);
    };
  }, [load]);

  return { job, loading, error, reload: load };
}

const _offerActionLocks = new Set();

export async function createJobOffer({ contactId, subId, permitOwner = 'sub', permitRequired = true }) {
  const CRM = window.CRM;
  if (!CRM || typeof CRM.__invokeFn !== 'function') return { ok: false, error: 'Supabase not loaded' };
  if (!contactId) return { ok: false, error: 'no contact' };
  if (!subId) return { ok: false, error: 'no sub' };
  const lockKey = `create:${contactId}:${subId}`;
  if (_offerActionLocks.has(lockKey)) return { ok: false, inFlight: true };
  _offerActionLocks.add(lockKey);
  try {
    const { data, error } = await CRM.__invokeFn('sub-offer-create', {
      body: {
        contact_id: contactId,
        sub_id: subId,
        permit_owner: permitOwner,
        permit_required: permitRequired,
      },
    });
    if (error) return { ok: false, error: await subFnErrorDetail(error) };
    if (data && data.error) return { ok: false, error: data.error };
    if (!data || !data.offer_id) return { ok: false, error: 'no offer id returned' };
    const link = data.link || null;
    let copied = false;
    if (link && window.copyText) {
      try { copied = !!(await window.copyText(link)); } catch (_e) { copied = false; }
    }
    dispatchSubChanged();
    return { ok: true, offerId: data.offer_id, link, copied, payoutAmount: data.payout_amount };
  } catch (e) {
    return { ok: false, error: String((e && e.message) || e) };
  } finally {
    _offerActionLocks.delete(lockKey);
  }
}

// Whitelisted patch only (never spread caller object into the body).
export async function editJobOffer(offerId, patch) {
  const CRM = window.CRM;
  if (!CRM || typeof CRM.__invokeFn !== 'function') return { ok: false, error: 'Supabase not loaded' };
  if (!offerId) return { ok: false, error: 'no offer' };
  if (!patch || typeof patch !== 'object') return { ok: false, error: 'no changes' };
  if (_offerActionLocks.has(offerId)) return { ok: false, inFlight: true };
  _offerActionLocks.add(offerId);
  const ALLOWED = [
    'timeframe_estimate', 'firm_install_date', 'payout_amount', 'payout_revised_reason',
    'est_labor_hours', 'permit_description', 'scope_json', 'permit_owner', 'permit_required',
    'materials_ship_status', 'materials_shipped_at', 'materials_received_at', 'materials_tracking',
  ];
  try {
    const body = { offer_id: offerId };
    ALLOWED.forEach(k => {
      if (Object.prototype.hasOwnProperty.call(patch, k)) body[k] = patch[k];
    });
    const { data, error } = await CRM.__invokeFn('sub-offer-edit', { body });
    if (error) return { ok: false, error: await subFnErrorDetail(error) };
    if (data && data.error) return { ok: false, error: data.error };
    dispatchSubChanged();
    const calendar = data && data.calendar ? data.calendar : null;
    if (calendar && ['created', 'updated', 'adopted'].includes(calendar.action)) {
      window.dispatchEvent(new CustomEvent('crm-data-changed', { detail: { table: 'calendar_events' } }));
    }
    return { ok: true, offer: data && data.offer ? data.offer : null, calendar };
  } catch (e) {
    return { ok: false, error: String((e && e.message) || e) };
  } finally {
    _offerActionLocks.delete(offerId);
  }
}

