// Hard delete: never reachable on a signed/approved row (PROPOSAL_DELETABLE_
// STATUSES). Exact FK-detach mirror of deleteProposal (crm-right.jsx:5877-
// 5903: clear proposals.superseded_by pointing at this row, clear
// invoices.proposal_id pointing at this row, THEN delete) PLUS the
// server-side status guard the bespoke lacks (fix pass): a zero-row delete
// is reported honestly instead of silently removing nothing while the UI
// already dropped the row from the local list.
//
// Capture-and-restore (fix pass, HIGH): the two FK-detach writes above MUST
// commit before the delete (the FK constraints require it), which means they
// commit even on a delete that then gets refused by the .in() status guard,
// a race between this function starting and the row moving past a
// deletable status underneath it. Left as-is, a refused delete permanently
// orphans every proposal that pointed at this one via superseded_by and
// every invoice that pointed at it via proposal_id, forever, since nothing
// ever re-links them. So: (a) capture the ids that are about to be detached
// BEFORE detaching, (b) probe the live status and refuse early when it is
// already unambiguously non-deletable (skips the detach entirely in the
// common case), (c) detach, (d) attempt the guarded delete, (e) on a
// zero-row result (the race), restore the captured links so a refused
// delete never leaves anything orphaned. A restore failure is non-fatal
// (console.warn) and folds into the same honest refusal message so the
// caller's toast tells Key to go check the proposal by hand.
export async function deleteProposal(proposal) {
  const CRM = window.CRM;
  if (!CRM || !CRM.__db || !proposal) return { ok: false, error: 'no db/proposal' };

  // (a) Capture, before anything is detached.
  const [supersededRes, invoiceRes] = await Promise.all([
    CRM.__db.from('proposals').select('id').eq('superseded_by', proposal.id),
    CRM.__db.from('invoices').select('id').eq('proposal_id', proposal.id),
  ]);
  const supersededIds = (supersededRes.data || []).map(r => r.id);
  const invoiceIds = (invoiceRes.data || []).map(r => r.id);

  // (b) Probe the live status. Only refuses early on an UNAMBIGUOUS row (a
  // real single row came back with a status outside the deletable list);
  // an empty/ambiguous result (not found, or a stub db with no real rows)
  // falls through to the authoritative guarded delete below rather than
  // refusing on a false negative.
  const { data: probeRows, error: probeErr } = await CRM.__db.from('proposals')
    .select('id, status').eq('id', proposal.id);
  if (probeErr) return { ok: false, error: probeErr.message };
  const probeRow = Array.isArray(probeRows) && probeRows.length ? probeRows[0] : null;
  if (probeRow && !PROPOSAL_DELETABLE_STATUSES.includes(probeRow.status)) {
    return { ok: false, statusChanged: true, error: 'This proposal changed status and can no longer be deleted' };
  }

  // (c) Detach.
  await CRM.__db.from('proposals').update({ superseded_by: null }).eq('superseded_by', proposal.id);
  await CRM.__db.from('invoices').update({ proposal_id: null }).eq('proposal_id', proposal.id);

  // (d) Guarded delete.
  const { data, error } = await CRM.__db.from('proposals')
    .delete()
    .eq('id', proposal.id)
    .in('status', PROPOSAL_DELETABLE_STATUSES)
    .select();
  if (error) return { ok: false, error: error.message };

  if (!data || data.length === 0) {
    // (e) Race: the row moved between the probe and the delete. Restore
    // exactly what the detach step above just cleared.
    let restoreFailed = false;
    if (supersededIds.length) {
      const { error: rErr } = await CRM.__db.from('proposals')
        .update({ superseded_by: proposal.id }).in('id', supersededIds);
      if (rErr) { restoreFailed = true; console.warn('[deleteProposal restore] superseded_by failed:', rErr.message); }
    }
    if (invoiceIds.length) {
      const { error: rErr } = await CRM.__db.from('invoices')
        .update({ proposal_id: proposal.id }).in('id', invoiceIds);
      if (rErr) { restoreFailed = true; console.warn('[deleteProposal restore] proposal_id failed:', rErr.message); }
    }
    return {
      ok: false, statusChanged: true,
      error: restoreFailed
        ? 'This proposal changed status and can no longer be deleted. Some links may not have restored, check this proposal.'
        : 'This proposal changed status and can no longer be deleted',
    };
  }

  const arr = CRM.proposals || [];
  const idx = arr.findIndex(p => p.id === proposal.id);
  if (idx >= 0) arr.splice(idx, 1);
  bumpProposals();
  window.dispatchEvent(new CustomEvent('crm-data-changed'));
  return { ok: true };
}

// Customer-facing proposal link, exact mirror of proposalUrl (crm-right.jsx:
// 6183). Null when the row has no token yet, a draft that never saved a
// token would otherwise hand a "null" URL to a customer.
export function proposalLinkUrl(proposal) {
  return (proposal && proposal.token) ? `https://backuppowerpro.com/proposal.html?token=${proposal.token}` : null;
}

// Shared promote-on-send/copy write, exact mirror of the .in(['Created',
// 'Draft','draft']) guard both sendLink and copyLink apply server-side
// (crm-right.jsx:6285-6288, 6323-6326), matching the bespoke's own
// unconditional attempt: it never client-gates the WRITE on any local
// status, it just always fires the guarded update and lets the server-side
// .in() decide (idempotent, harmless on a non-draft row).
//
// Fix pass (MED-HIGH): the prior version gated on the PASSED-IN `proposal`
// parameter's own `.status` before resolving the live row
// (`if (!proposal || proposal.status !== 'draft') return;`), a stale
// snapshot check. A caller holding an out-of-date `proposal` reference
// (status read before the live CRM.proposals row was remapped elsewhere)
// could show a status that no longer matches the DB, and a stale
// proposal.status !== 'draft' would return here immediately, PERMANENTLY
// skipping the promotion write even though the live row genuinely still
// needed it. Fixed by reading the freshest `live` row (resolved from
// CRM.proposals, not the parameter) and, separately, always firing the
// guarded write regardless: the write is never blocked by any status read,
// stale or fresh, only the local OPTIMISTIC FLIP is (so sending a deposit
// link on an already-signed proposal, for instance, never gets its local
// display corrupted to "sent"; the server-side .in() guard already refuses
// the write there, this just keeps the local view from disagreeing with it
// in the meantime).
//
// Best-effort: the SMS/clipboard action already succeeded by the time this
// runs. A definite write ERROR reverts the flip (this was really a draft
// that failed to promote, tell the console why). A zero-row result with NO
// error is left as-is, never reverted: in production that means the row
// had already moved past draft by the time the write landed (the flip is
// then a correct no-op or self-heals on the next realtime refetch); under
// TEST_MODE the stub db (crm/v3/crm-data.js __makeStubDb) always resolves
// {data:[], error:null} regardless of whether the guard matched, so
// reverting on a zero-row result here would leave every promoted fixture
// looking unsent forever under ?test=1.
async function promoteProposalIfDraft(proposal) {
  const CRM = window.CRM;
  if (!CRM || !proposal) return;
  const live = (CRM.proposals || []).find(p => p.id === proposal.id) || proposal;
  const wasDraft = live.status === 'draft';
  const prevStatus = live.status;
  const prevSentAt = live.sent_at;
  const prevCopiedAt = live.copied_at;
  const nowIso = new Date().toISOString();
  if (wasDraft) {
    live.status = 'sent';
    live.sent_at = nowIso;
    live.copied_at = nowIso;
    bumpProposals();
    window.dispatchEvent(new CustomEvent('crm-data-changed'));
  }
  if (!CRM.__db || !proposal.token) return;
  const revert = (reason) => {
    if (!wasDraft) return;
    const liveNow = (CRM.proposals || []).find(p => p.id === proposal.id) || live;
    liveNow.status = prevStatus;
    liveNow.sent_at = prevSentAt;
    liveNow.copied_at = prevCopiedAt;
    bumpProposals();
    window.dispatchEvent(new CustomEvent('crm-data-changed'));
    console.warn('[promoteProposalIfDraft] failed:', reason);
  };
  try {
    const { error } = await CRM.__db.from('proposals')
      .update({ status: 'Sent', copied_at: nowIso, sent_at: nowIso })
      .eq('token', proposal.token)
      .in('status', ['Created', 'Draft', 'draft']);
    if (error) revert(error.message);
  } catch (e) {
    revert(String((e && e.message) || e));
  }
}

// Send the proposal link via SMS + promote draft -> Sent. Exact guard +
// payload mirror of sendLink's proposal path (crm-right.jsx:6229-6297):
// no-token refusal, do_not_contact refusal, in-flight lock keyed
// contact.id::url, minute-bucketed idempotency key, the two body-string
// variants (deposit-ask vs generic, read verbatim off crm-right.jsx:6248-
// 6250). depositAsk is the CALLER's decision (mirrors the bespoke's own
// FinanceRow primary-button construction, crm-right.jsx:6384-6388, a
// UI-level choice: depositAsk=true only when the row's status is 'signed').
export async function sendProposalLink(proposal, contact, depositAsk = false) {
  const CRM = window.CRM;
  const url = proposalLinkUrl(proposal);
  if (!url) return { ok: false, error: 'No link yet, save the draft first' };
  if (!contact || !contact.id) return { ok: false, error: 'No contact' };
  if (contact.do_not_contact) return { ok: false, error: 'Marked do not contact, cannot send' };
  if (!CRM || typeof CRM.__invokeFn !== 'function') return { ok: false, error: 'Supabase not loaded' };
  const lockKey = `${contact.id}::${url}`;
  if (_proposalSendLocks.has(lockKey)) return { ok: false, inFlight: true };
  _proposalSendLocks.add(lockKey);
  const body = depositAsk
    ? `Here's the deposit link for your signed proposal from Backup Power Pro: ${url}`
    : `Here's your update from Backup Power Pro: ${url}`;
  const minute = Math.floor(Date.now() / 60000);
  // 'prop' (fix pass, parity): the bespoke derives this same literal from a
  // linkKind switch (crm-right.jsx:6259-6260, linkUrl.includes('/proposal.
  // html') -> 'prop'); this port had drifted to the longer word 'proposal',
  // which meant a rapid double-send of the SAME proposal from the bespoke
  // desktop face and this Ionic face built two DIFFERENT idempotency keys
  // for the same minute, so the send-sms edge fn's own dedupe could not
  // catch a genuine cross-face double-tap.
  const idempotencyKey = `v3-send-${contact.id}-prop-${minute}`;
  try {
    const { data, error } = await CRM.__invokeFn('send-sms', { body: { contactId: contact.id, body, idempotencyKey } });
    if (error || (data && data.success === false)) {
      return { ok: false, error: (error && error.message) || (data && data.error) || 'unknown' };
    }
    await promoteProposalIfDraft(proposal);
    return { ok: true };
  } catch (e) {
    return { ok: false, error: String((e && e.message) || e) };
  } finally {
    setTimeout(() => _proposalSendLocks.delete(lockKey), 2000);
  }
}

// Copy the proposal link to the clipboard + the identical promote write (no
// SMS). Exact mirror of copyLink's proposal path (crm-right.jsx:6305-6337).
// No in-flight lock, matches the bespoke, a clipboard write is effectively
// instant and idempotent to repeat.
export async function copyProposalLink(proposal, contact) {
  const url = proposalLinkUrl(proposal);
  if (!url) return { ok: false, error: 'No link yet, save the draft first' };
  const copied = window.copyText ? await window.copyText(url) : false;
  await promoteProposalIfDraft(proposal);
  return copied ? { ok: true } : { ok: false, error: 'Copy failed' };
}

// FIX 3 (task spec, honesty bug the scout found): the bespoke's own proposal
// email gate checks a DEAD literal inside its status-exclusion array
// (crm-right.jsx:6541, `!['declined','cancelled','expired','superseded']
// .includes(status)`), but 'superseded' is never an actual status VALUE
// anywhere in this codebase, superseding sets the separate superseded_at
// COLUMN and leaves status untouched (see createProposal's supersede write
// above). That means a superseded ghost draft (fixture t-pr7) still passes
// the bespoke's own gate and could be emailed to a customer as if it were
// live. Fixed here: gate on proposal.superseded_at directly instead of the
// dead literal.
export function canEmailProposal(proposal) {
  return !!proposal && !!proposalLinkUrl(proposal) && !proposal.superseded_at
    && !['declined', 'cancelled', 'expired'].includes(proposal.status);
}

// ── Invoice CRUD + send-SMS/copy-link promotion (Increment P) ───────────
// Exact mirrors of NewInvoiceModal.submit (crm/v3/crm-right.jsx:10418-10484,
// create/edit), deleteInvoice (crm-right.jsx:5904-5920), and the invoice
// halves of sendLink/copyLink (crm-right.jsx:6229-6337), same optimistic-
// mutate / re-resolve-by-id / bump-before-dispatch invariants as every
// other helper in this file.
//
// DISCLOSED SCOPE CUT (not a byte-exact UI mirror, a deliberate decision):
// the composer built on top of this (InvoiceComposerModal, ionic-app.jsx)
// only offers name+amount line-item rows with add/remove, no discount-line
// toggle, no deposit/final/balance quick-preset buttons, no drag-reorder.
// The SAVE payload and the create-time DEFAULT preset (the deposit-rate
// line item, matching the bespoke's own default, crm-right.jsx:10354-10365)
// are still exact; total() below still supports a 'discount' kind line item
