// Customer-facing invoice link, exact mirror of invoiceUrl (crm-right.jsx:
// 6184). Null when the row has no token yet, a draft that never saved a
// token would otherwise hand a "null" URL to a customer.
export function invoiceLinkUrl(invoice) {
  return (invoice && invoice.token) ? `https://backuppowerpro.com/invoice.html?token=${invoice.token}` : null;
}

// Statuses an existing invoice may be edited FROM (fix pass addition, the
// bespoke's own onEdit gate has NO server-side status guard at all,
// crm-right.jsx:10454, an edit could otherwise silently overwrite a paid/
// voided row underneath a stale tab). Defensive casing list: invoices.status
// has never been observed written Title-Case in production (unlike
// proposals, which do write 'Viewed'/'Copied' Title-Case, see
// PROPOSAL_EDITABLE_STATUSES above), but kept defensive rather than assuming
// that never changes, same convention as every other .in() guard here.
const INVOICE_EDITABLE_STATUSES = ['draft', 'Draft', 'sent', 'Sent', 'unpaid', 'Unpaid', 'overdue', 'Overdue'];

// Statuses an existing invoice may be hard-deleted FROM: every non-final
// status, EXCLUDING 'paid' (task spec, byte-exact list). Same defensive-
// casing convention as above.
const INVOICE_DELETABLE_STATUSES = [
  'draft', 'Draft', 'sent', 'Sent', 'unpaid', 'Unpaid', 'overdue', 'Overdue',
  'voided', 'Voided', 'refunded', 'Refunded', 'cancelled', 'Cancelled',
];

// Minimal shape mirror of crm/v3/crm-data.js's mapInvoice, used ONLY as a
// defensive fallback (same convention as mapProposalMinimal above):
// window.mapInvoice is reachable in every real boot path, this branch never
// fires there, and self-heals on the next realtime whole-table refetch.
function mapInvoiceMinimal(r, totalDollars) {
  const rawStatus = (r.status || 'draft').toLowerCase();
  const status = (rawStatus === 'unpaid' || rawStatus === 'open') ? 'sent' : rawStatus;
  return {
    id: r.id, token: r.token || null, contact_id: r.contact_id, proposal_id: r.proposal_id || null,
    amount_cents: r.total != null ? Math.round(Number(r.total) * 100) : Math.round((totalDollars || 0) * 100),
    paid_cents: 0, payments: [],
    kind: r.kind || 'final', status,
    sent_at: r.sent_at || r.created_at || null, viewed_at: r.viewed_at || null, paid_at: r.paid_at || null,
    payment_method: r.payment_method || null,
    line_items: Array.isArray(r.line_items) ? r.line_items : [],
    creator_version: r.creator_version || 'v3',
  };
}
function mapInvoiceRow(r) {
  return (typeof window.mapInvoice === 'function') ? window.mapInvoice(r) : mapInvoiceMinimal(r, Number(r.total) || 0);
}

// Build the invoice payload NewInvoiceModal.submit writes (crm-right.jsx:
// 10435-10451). `invoice` is the LIVE row being edited (null on create), used
// only to preserve its existing proposal_id when the caller has no fresher
// proposal context to hand in.
function buildInvoicePayload({ contact, proposal, invoice, lineItems, total }) {
  const storedItems = lineItems.map(li => ({
    id: li.id, kind: li.kind || 'item', name: li.name || '',
    amount: Number(li.amount) || 0, checked: li.checked !== false,
    discountType: li.discountType || undefined,
  }));
  return {
    contact_id: contact.id,
    proposal_id: (proposal && proposal.id) || (invoice && invoice.proposal_id) || null,
    contact_name: contact.name || '',
    contact_email: contact.email || '',
    contact_phone: contact.phone || '',
    contact_address: contact.address || '',
    creator_version: 'v3',
    line_items: storedItems,
    total,
  };
}

// Create an invoice. Exact insert-payload mirror of NewInvoiceModal.submit's
// create branch (crm-right.jsx:10441-10459): initial status 'draft', then an
// optimistic push via mapInvoiceRow (the same mapper the realtime refetch
// path uses).
export async function createInvoice({ contact, proposal, lineItems, total }) {
  const CRM = window.CRM;
  if (!CRM || !CRM.__db) return { ok: false, error: 'Supabase not loaded' };
  if (!contact || !contact.id) return { ok: false, error: 'No contact' };
  if (!(Number(total) > 0)) return { ok: false, error: 'Total must be greater than 0' };
  if (contact.do_not_contact) return { ok: false, error: 'Marked do not contact, cannot send' };

  const payload = buildInvoicePayload({ contact, proposal, invoice: null, lineItems, total });
  const { data, error } = await CRM.__db.from('invoices')
    .insert([{ ...payload, status: 'draft' }]).select().single();
  if (error || !data) return { ok: false, error: (error && error.message) || 'unknown' };

  const mapped = mapInvoiceRow(data);
  const arr = CRM.invoices || [];
  const idx = arr.findIndex(i => i.id === mapped.id);
  if (idx >= 0) arr[idx] = mapped; else arr.unshift(mapped);
  bumpInvoices();
  window.dispatchEvent(new CustomEvent('crm-data-changed'));
  return { ok: true, invoice: mapped };
}

// Edit an existing invoice. Exact payload mirror of the same submit()
// (crm-right.jsx:10441-10454, isEdit branch) PLUS the .in(INVOICE_EDITABLE_
// STATUSES) guard the bespoke lacks (fix pass, same reasoning as
// updateProposal above): a zero-row result is reported honestly instead of
// silently no-oping.
export async function updateInvoice(invoice, { contact, proposal, lineItems, total }) {
  const CRM = window.CRM;
  if (!CRM || !CRM.__db || !invoice) return { ok: false, error: 'no db/invoice' };
  if (!(Number(total) > 0)) return { ok: false, error: 'Total must be greater than 0' };

  const live = (CRM.invoices || []).find(i => String(i.id) === String(invoice.id)) || invoice;
  const payload = buildInvoicePayload({
    contact: contact || { id: live.contact_id }, proposal, invoice: live, lineItems, total,
  });

  const { data, error } = await CRM.__db.from('invoices')
    .update(payload)
    .eq('id', invoice.id)
    .in('status', INVOICE_EDITABLE_STATUSES)
    .select();
  if (error) return { ok: false, error: error.message };
  if (!data || data.length === 0) {
    return { ok: false, statusChanged: true, error: 'This invoice changed status and can no longer be edited' };
  }
  const mapped = mapInvoiceRow(data[0]);
  const arr = CRM.invoices || [];
  const idx = arr.findIndex(i => i.id === mapped.id);
  if (idx >= 0) arr[idx] = mapped; else arr.push(mapped);
  bumpInvoices();
  window.dispatchEvent(new CustomEvent('crm-data-changed'));
  return { ok: true, invoice: mapped };
}

// Hard delete. FIX-NOT-COPY (task spec): the bespoke's own deleteInvoice
// (crm-right.jsx:5904-5920) has NEITHER a payment-history pre-check NOR a
// status guard, so it can silently destroy an invoice with real payment
// history attached (the customer's receipt trail) or race a status change
// underneath it. This port refuses honestly on both:
//  (a) a client-side pre-check against the invoice's own mapped `.payments`
//      array, the equivalent aggregate to window.CRM.__paymentsByInvoice
//      (a crm-data.js-PRIVATE variable, never exposed on window; mapInvoice
//      already folds it onto every invoice row as `.payments`, crm/v3/
//      crm-data.js:1219-1222, so reading invoice.payments is the reachable
//      equivalent);
//  (b) a server-side .in(INVOICE_DELETABLE_STATUSES) guard excluding 'paid'.
export async function deleteInvoice(invoice) {
  const CRM = window.CRM;
  if (!CRM || !CRM.__db || !invoice) return { ok: false, error: 'no db/invoice' };
  const live = (CRM.invoices || []).find(i => String(i.id) === String(invoice.id)) || invoice;
  // live.payments is only populated at load/refetch time; a partial payment
  // recorded moments earlier patches live.paid_cents (both the payments-
  // realtime handler, crm/v3/crm-data.js:1920-1928, and recordPayment's own
  // optimistic patch) WITHOUT refreshing live.payments, so a payments-array
  // check alone leaves a staleness window where record-payment-then-delete
  // on the same invoice slips past this pre-check and hits a raw Postgres
  // FK-violation toast instead of this honest refusal. Check both signals.
  if ((Array.isArray(live.payments) && live.payments.length > 0) || Number(live.paid_cents) > 0) {
    return { ok: false, refused: true, error: 'This invoice has payment history and cannot be deleted' };
  }
  const { data, error } = await CRM.__db.from('invoices')
    .delete()
    .eq('id', invoice.id)
    .in('status', INVOICE_DELETABLE_STATUSES)
    .select();
  if (error) return { ok: false, error: error.message };
  if (!data || data.length === 0) {
    return { ok: false, statusChanged: true, error: 'This invoice changed status and can no longer be deleted' };
  }
  const arr = CRM.invoices || [];
  const idx = arr.findIndex(i => i.id === invoice.id);
  if (idx >= 0) arr.splice(idx, 1);
  bumpInvoices();
  window.dispatchEvent(new CustomEvent('crm-data-changed'));
  return { ok: true };
}

// Re-entrancy lock for invoice SMS sends, same convention as
// _proposalSendLocks above.
const _invoiceSendLocks = new Set();

// Shared promote-on-send/copy write for invoices, factored next to
// promoteProposalIfDraft above (SAME always-write + gated-optimistic-flip +
// revert-on-error contract): exact mirror of the invoice branch both
// sendLink and copyLink apply server-side (crm-right.jsx:6289-6294,
// 6327-6331), .in(['draft','Draft']). Best-effort: the SMS/clipboard action
// already succeeded by the time this runs; a definite write ERROR reverts
// the optimistic flip, a zero-row result with no error is left as-is (see
// promoteProposalIfDraft's own comment for the full TEST_MODE reasoning,
// identical here).
async function promoteInvoiceIfDraft(invoice) {
  const CRM = window.CRM;
  if (!CRM || !invoice) return;
  const live = (CRM.invoices || []).find(i => i.id === invoice.id) || invoice;
  const wasDraft = live.status === 'draft';
  const prevStatus = live.status;
  const prevSentAt = live.sent_at;
  const nowIso = new Date().toISOString();
  if (wasDraft) {
    live.status = 'sent';
    live.sent_at = nowIso;
    bumpInvoices();
    window.dispatchEvent(new CustomEvent('crm-data-changed'));
  }
  if (!CRM.__db || !invoice.token) return;
  const revert = (reason) => {
    if (!wasDraft) return;
    const liveNow = (CRM.invoices || []).find(i => i.id === invoice.id) || live;
    liveNow.status = prevStatus;
    liveNow.sent_at = prevSentAt;
    bumpInvoices();
    window.dispatchEvent(new CustomEvent('crm-data-changed'));
    console.warn('[promoteInvoiceIfDraft] failed:', reason);
  };
  try {
    const { error } = await CRM.__db.from('invoices')
      .update({ status: 'unpaid', sent_at: nowIso })
      .eq('token', invoice.token)
      .in('status', ['draft', 'Draft']);
    if (error) revert(error.message);
  } catch (e) {
    revert(String((e && e.message) || e));
  }
}

// Send the invoice link via SMS + promote draft -> unpaid. Exact guard +
// payload mirror of sendLink's invoice path (crm-right.jsx:6229-6297): the
// invoice branch NEVER sends the deposit-ask body variant (only a signed
// proposal's Send button ever passes depositAsk=true, crm-right.jsx:
// 6384-6388), no-token refusal, do_not_contact refusal, in-flight lock keyed
// contact.id::url, minute-bucketed idempotency key with the 'inv' literal
// (crm-right.jsx:6259-6260).
export async function sendInvoiceLink(invoice, contact) {
  const CRM = window.CRM;
  const url = invoiceLinkUrl(invoice);
  if (!url) return { ok: false, error: 'No link yet, save the draft first' };
  if (!contact || !contact.id) return { ok: false, error: 'No contact' };
  if (contact.do_not_contact) return { ok: false, error: 'Marked do not contact, cannot send' };
  if (!CRM || typeof CRM.__invokeFn !== 'function') return { ok: false, error: 'Supabase not loaded' };
  const lockKey = `${contact.id}::${url}`;
  if (_invoiceSendLocks.has(lockKey)) return { ok: false, inFlight: true };
  _invoiceSendLocks.add(lockKey);
  const body = `Here's your update from Backup Power Pro: ${url}`;
  const minute = Math.floor(Date.now() / 60000);
  const idempotencyKey = `v3-send-${contact.id}-inv-${minute}`;
  try {
    const { data, error } = await CRM.__invokeFn('send-sms', { body: { contactId: contact.id, body, idempotencyKey } });
    if (error || (data && data.success === false)) {
      return { ok: false, error: (error && error.message) || (data && data.error) || 'unknown' };
    }
    await promoteInvoiceIfDraft(invoice);
    return { ok: true };
  } catch (e) {
    return { ok: false, error: String((e && e.message) || e) };
  } finally {
    setTimeout(() => _invoiceSendLocks.delete(lockKey), 2000);
  }
}

// Copy the invoice link to the clipboard + the identical promote write (no
// SMS). Exact mirror of copyLink's invoice path (crm-right.jsx:6305-6337).
// No in-flight lock, matches the bespoke, a clipboard write is effectively
// instant and idempotent to repeat. `contact` unused here (kept only for
// call-signature symmetry with copyProposalLink above).
export async function copyInvoiceLink(invoice, contact) {
  const url = invoiceLinkUrl(invoice);
  if (!url) return { ok: false, error: 'No link yet, save the draft first' };
  const copied = window.copyText ? await window.copyText(url) : false;
  await promoteInvoiceIfDraft(invoice);
  return copied ? { ok: true } : { ok: false, error: 'Copy failed' };
}

// ── Email flows, ALL send-email templates (Increment P) ─────────────────
// Port of emailDoc (crm/v3/crm-right.jsx:5935-6138). permit-approved /
// completion / review templates are DEAD in the bespoke (never wired to any
// live button, task spec confirms) and are deliberately NOT ported here.

const EMAIL_SUBJECTS = {
  proposal: 'Your generator inlet quote from Backup Power Pro',
  invoice: 'Invoice from Backup Power Pro',
  receipt: 'Paid in full, your receipt from Backup Power Pro',
  'receipt-deposit': 'Deposit received, your install is booked',
  'receipt-partial': 'Payment received, your updated balance',
  'refund-receipt': 'Your refund from Backup Power Pro',
  'ach-failed': "Your bank transfer did not clear, here's how to finish",
  // completion went LIVE 2026-07-13 (the Completion Packet arc); the old
  // "deliberately not ported, dead in the bespoke" note above is obsolete.
  completion: "You're all set, backup power confirmed",
};
const EMAIL_TPL_LABEL = {
  proposal: 'quote', invoice: 'invoice', receipt: 'paid-in-full receipt',
  'receipt-deposit': 'deposit receipt', 'receipt-partial': 'balance receipt',
  'refund-receipt': 'refund receipt', 'ach-failed': 'bank-transfer retry notice',
  completion: 'completion packet',
};

// ── Completion Packet (Ionic parity of runCompletionPacket, crm-right.jsx;
// docs/qa/COMPLETION-PACKET-PLAN.md). Two halves so the UI can put the
// issue confirm BEFORE any write: find first (a reused packet means the tap
// is a resend, never a duplicate certificate), then issue, with the honest
// attest-on-409 path surfaced to the caller as { needAttest: true }. ──
const _packetIssueLocks = new Set();

export async function findIssuedCompletionPacket(contactId) {
  const CRM = window.CRM;
  const { data } = await CRM.__db.from('completion_packets')
    .select('id,token,status,permit_required,jurisdiction_name,inspection_passed_at,issued_at')
    .eq('contact_id', contactId).eq('status', 'issued')
    .order('issued_at', { ascending: false }).limit(1);
  return (data && data[0]) || null;
}

export async function issueCompletionPacket(contactId, opts) {
  // In-flight claim AT ENTRY (the sync-lock scar): a double tap can never
  // race two issues for the same contact.
  if (_packetIssueLocks.has(contactId)) return { ok: false, inFlight: true };
  _packetIssueLocks.add(contactId);
  try {
    const CRM = window.CRM;
    const attest = !!(opts && opts.attest);
    const body = attest
      ? { action: 'issue', contact_id: contactId, attest_inspection_pass: true }
      : { action: 'issue', contact_id: contactId };
    const { data, error } = await CRM.__invokeFn('completion-packet', { body });
    if (error) {
      let errBody = null;
      try { errBody = await (error.context && error.context.json && error.context.json()); } catch (_e) { /* opaque */ }
      if (errBody && errBody.error === 'no_inspection_pass') return { ok: false, needAttest: true };
      return { ok: false, error: (errBody && (errBody.detail || errBody.error)) || error.message || 'issue failed' };
    }
    if (!data || !data.packet) return { ok: false, error: 'no packet returned' };
    return { ok: true, packet: data.packet };
  } finally {
    _packetIssueLocks.delete(contactId);
  }
}

// Exact mirror of the inline fmtC formatter in emailDoc (crm-right.jsx:6003,
// 6021, 6035): 'en-US', min 0 / max 2 fraction digits.
function fmtCentsUSD(c) {
  return '$' + (Math.round(c) / 100).toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 2 });
}

// window.formatDate(iso, opts) is exported by crm/v3/crm-shared.jsx (side-
// effect imported in ionic-app.jsx); the long-form options mirror emailDoc's
// own calls (crm-right.jsx:5991, 6009, 6025). Local fallback matches
// formatDateOf's own defensive pattern above.
function formatLongDate(iso) {
  if (window.formatDate) return window.formatDate(iso, { month: 'long', day: 'numeric', year: 'numeric' });
  const d = new Date(iso);
  return isNaN(d.getTime()) ? '' : d.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
}

// Shared paid/remaining clamp, reused by FIX 4, the balance-receipt block,
// and the ach-failed block below (all three run the SAME clamp the bespoke
// repeats three times near-identically, crm-right.jsx:6000-6002/6033-6034).
function invoiceBalanceCents(invoice) {
  const totalC = (invoice && invoice.amount_cents) || 0;
  const paidC = Math.min((invoice && invoice.paid_cents) || 0, totalC);
  return { totalC, paidC, balC: Math.max(0, totalC - paidC) };
}

// Pure computation of subject + template variables + preview metadata, exact
// mirror of emailDoc's variable-building block (crm-right.jsx:5953-6053,
// minus permit-approved/completion/review). No network here; the dry-run
// fetch is a separate function below so the modal can render the metadata
// instantly and let the body-preview link arrive a beat later.
//
// FIX 4 (task spec, customer-trust bug the scout found): for template
// 'invoice', when the invoice already has money in (paid_cents > 0), `total`
// reads as the REMAINING balance, never the full price (the invoice
// template renders "Pay {{total}} securely"). The bespoke always sent the
// FULL invoice.amount_cents here unconditionally, so a customer who already
// paid a deposit would open an email demanding the entire job price again.
export function buildEmailFields({ template, contact, proposal, invoice, packet }) {
  const isBalanceReceipt = template === 'receipt-deposit' || template === 'receipt-partial';
  const certUrl = packet && packet.token ? `https://backuppowerpro.com/certificate.html?token=${packet.token}` : null;
  const url = template === 'completion'
    ? certUrl
    : template === 'receipt'
    ? (invoice && invoice.token ? `https://backuppowerpro.com/receipt.html?token=${invoice.token}` : null)
    : isBalanceReceipt ? null
    : (proposal ? proposalLinkUrl(proposal) : (invoice ? invoiceLinkUrl(invoice) : null));
  const total = ((proposal && proposal.amount_cents) || (invoice && invoice.amount_cents) || 0) / 100;
  const firstName = firstNameOf(contact);
  const subject = EMAIL_SUBJECTS[template] || `Update from Backup Power Pro for ${firstName}`;
  const variables = {
    [`${template}_url`]: url,
    total: '$' + total.toLocaleString(),
    amp_type: (proposal && proposal.amp_type) || '30',
    first_name: firstName,
  };
  if (template === 'invoice' && invoice) {
    variables.invoice_num = (invoice.id || '').slice(0, 8).toUpperCase();
    const { paidC, balC } = invoiceBalanceCents(invoice);
    if (paidC > 0) variables.total = fmtCentsUSD(balC); // FIX 4
  }
  if (template === 'proposal' && proposal) variables.quote_num = (proposal.id || '').slice(0, 8).toUpperCase();
  // Completion packet (parity of the bespoke sendCompletionEmail,
  // crm-right.jsx): the certificate + guide CTAs and the honest permit_line
  // composed from the FROZEN packet, never re-derived from live rows.
  if (template === 'completion' && packet) {
    variables.certificate_url = certUrl;
    variables.owner_guide_url = `https://backuppowerpro.com/owner-guide.html?token=${packet.token}`;
    const passDate = packet.inspection_passed_at ? formatLongDate(packet.inspection_passed_at) : '';
    variables.permit_line = packet.permit_required === false
      ? 'No county permit was required for your installation. Your certificate below is the permanent record.'
      : 'The county inspection is done' + (packet.jurisdiction_name ? ': ' + packet.jurisdiction_name + ' signed off' : '') + (passDate ? ' on ' + passDate : '') + '. Your certificate below is the permanent record.';
  }
  if (template === 'receipt' && invoice) {
    variables.receipt_num = (invoice.id || '').slice(0, 8).toUpperCase();
    variables.paid_date = invoice.paid_at ? formatLongDate(invoice.paid_at) : '';
    variables.payment_method = invoice.payment_method || '';
  }
  if (isBalanceReceipt && invoice) {
    const { totalC, paidC, balC } = invoiceBalanceCents(invoice);
    variables.total = fmtCentsUSD(totalC);
    variables.amount_paid = fmtCentsUSD(paidC);
    variables.paid_to_date = fmtCentsUSD(paidC);
    variables.balance_remaining = fmtCentsUSD(balC);
    variables.receipt_num = (invoice.id || '').slice(0, 8).toUpperCase();
    variables.paid_date = formatLongDate(invoice.paid_at || new Date().toISOString());
    variables.payment_method = invoice.payment_method || '';
  }
  if (template === 'refund-receipt' && invoice) {
    const totalC = invoice.amount_cents || 0;
    const refundedC = (invoice.payments || []).reduce((s, p) => s + Math.round((Number(p.refunded_amount) || 0) * 100), 0);
    const netC = Math.max(0, totalC - refundedC);
    variables.refund_amount = fmtCentsUSD(refundedC);
    variables.net_paid = fmtCentsUSD(netC);
    variables.total = fmtCentsUSD(totalC);
    variables.refund_date = formatLongDate(new Date().toISOString());
    variables.refund_method = /bank/i.test(invoice.payment_method || '') ? 'bank account' : 'card';
  }
  if (template === 'ach-failed' && invoice) {
    const { balC } = invoiceBalanceCents(invoice);
    variables.amount = fmtCentsUSD(balC);
    variables.retry_url = url || invoiceLinkUrl(invoice) || '';
  }
  const docNum = variables.invoice_num || variables.quote_num || variables.receipt_num || null;
  const isRefundReceipt = template === 'refund-receipt';
  const isAchFailed = template === 'ach-failed';
  const amountLabel = isRefundReceipt ? 'Refund' : isAchFailed ? 'Due' : isBalanceReceipt ? 'Balance' : 'Amount';
  // template === 'invoice' routes through variables.total, not a fresh
  // total.toLocaleString() computation, so the confirm modal's Amount row
  // matches the same balance-aware value FIX 4 already put in the outbound
  // email (variables.total is fmtCentsUSD(balC) once paid_cents > 0, the
  // full total otherwise). Without this, a partially-paid invoice showed
  // the confirm modal the full total while the email itself carried the
  // remaining balance, the one number Key confirms was not the number the
  // customer read.
  const amountVal = isRefundReceipt ? variables.refund_amount
    : isAchFailed ? variables.amount
    : isBalanceReceipt ? variables.balance_remaining
    : template === 'invoice' ? variables.total
    : (total ? '$' + total.toLocaleString() : null);
  return {
    url, subject, variables, docNum, amountLabel, amountVal, firstName,
    templateLabel: EMAIL_TPL_LABEL[template] || 'email',
  };
}

// Best-effort dry-run preview fetch (never blocks, never throws): mirrors
// emailDoc's own dry_run block (crm-right.jsx:6060-6074). Real network call
// in production; under ?test=1 the stub db resolves {data:null,error:null}
// for every functions.invoke call (crm/v3/crm-data.js __makeStubDb), so this
// always resolves the empty-preview shape there, zero real network, per the
// standing TEST-stub contract.
export async function fetchEmailDryRun({ template, contact, subject, variables }) {
  const CRM = window.CRM;
  if (!CRM || typeof CRM.__invokeFn !== 'function') return { emailPreviewUrl: null, dryRunWarning: null };
  try {
    const { data: dry } = await CRM.__invokeFn('send-email', {
      body: { template, contact_id: contact.id, subject, variables, trigger_source: 'crm_v3_finance_action', dry_run: true },
    });
    let emailPreviewUrl = null;
    if (dry && dry.html) {
      emailPreviewUrl = URL.createObjectURL(new Blob([dry.html], { type: 'text/html' }));
    }
    let dryRunWarning = null;
    if (dry && dry.would_block) {
      dryRunWarning = dry.sample_hit
        ? `This email still contains sample data ("${dry.sample_hit}") and would be REFUSED on send.`
        : `This email has unresolved placeholders (${(dry.unresolved_placeholders || []).slice(0, 3).join(', ')}) and would be REFUSED on send.`;
    }
    return { emailPreviewUrl, dryRunWarning };
  } catch (_) {
    return { emailPreviewUrl: null, dryRunWarning: null };
  }
}

// In-flight lock, keyed per contact (mirrors the bespoke's single
// sendingEmailRef, crm-right.jsx:5927, a per-ContactFinance-instance
// boolean; keyed here so two different contacts' emails can never block
// each other across pages/tabs).
const _emailSendLocks = new Set();

// The real send. Exact guard + payload mirror of emailDoc's send block
// (crm-right.jsx:6093-6138): !contact.email refusal, in-flight lock cleared
// in finally, real invoke (no dry_run), unwrapped server error detail,
// skipped-reason toasts in plain language (no raw enum), success dispatches
// 'crm-email-logged'. PLUS the fixes (task spec): (a) a successful
// 'proposal' send promotes a draft proposal to Sent (the email finally
// counts as sent); (b) a successful 'invoice' send promotes a draft invoice
// to unpaid (draft invoices are emailable, see the openActions gate in
// ionic-app.jsx, and must not stay draft forever); both wrapped so a promote
// failure never disturbs the sent toast. FIX 3 (canEmailProposal, above) and
// FIX 4 (the balance-aware `total`, in buildEmailFields above) are gating/
// computation concerns that belong to the CALLER, not this function, whose
// only job is to send exactly the subject/variables it is handed.
export async function sendDocEmail({ template, contact, proposal, invoice, subject, variables }) {
  if (!contact || !contact.email) return { ok: false, error: 'No email on contact, add one first', noEmail: true };
  const CRM = window.CRM;
  const lockKey = contact.id;
  if (_emailSendLocks.has(lockKey)) return { ok: false, inFlight: true };
  _emailSendLocks.add(lockKey);
  try {
    if (!CRM || typeof CRM.__invokeFn !== 'function') return { ok: false, error: 'Supabase not loaded' };
    const { data, error } = await CRM.__invokeFn('send-email', {
      body: { template, contact_id: contact.id, subject, variables, trigger_source: 'crm_v3_finance_action' },
    });
    if (error) {
      let detail = error.message || 'unknown';
      try {
        const body = await (error.context && error.context.json && error.context.json());
        if (body && body.error) detail = body.error + (body.need ? ` (needs: ${(body.need || []).join(', ')})` : '');
      } catch (_) { /* best-effort error-detail unwrap, never blocks the failure return */ }
      return { ok: false, error: detail };
    }
    if (data && data.skipped) {
      const skipMsg = {
        dnc: 'Not sent, this contact is marked do not contact.',
        no_email_on_file: 'Not sent, no email address on file for this contact.',
        marketing_opt_out: 'Not sent, this contact opted out of marketing emails.',
      }[data.skipped] || `Not sent: ${data.skipped}`;
      return { ok: false, skipped: data.skipped, error: skipMsg };
    }
    try {
      if (template === 'proposal' && proposal) await promoteProposalIfDraft(proposal);
      if (template === 'invoice' && invoice) await promoteInvoiceIfDraft(invoice);
    } catch (_) { /* best-effort, the email already sent, never disturb the sent toast */ }
    window.dispatchEvent(new CustomEvent('crm-email-logged', { detail: { contact_id: contact.id } }));
    return { ok: true, email: contact.email };
  } catch (e) {
    return { ok: false, error: String((e && e.message) || e) };
  } finally {
    _emailSendLocks.delete(lockKey);
  }
}

// ── Permits + materials write surfaces (Increment S1) ────────────────────
// Every helper below mirrors an existing bespoke control's write EXACTLY
// (crm/v3/crm-right.jsx PermitsCard/JurisdictionEditor/PermitStatusActions/
// MaterialRow/InstallSpecCard), same fields, same forward-only stage guard,
// same optimistic-mutate/re-resolve-by-id/revert-on-error contract every
// other write in this file already follows. window.CRM's own
// advanceJobSubmitPermit/advanceJobMarkApproved/advanceJobVerifyPermit/
// advanceJobUnverifyPermit (crm/v3/crm-data.js) are reused directly where the
// action already exists there (the AdvanceJobCard's one-tap actions); the
// helpers below cover the controls that only ever existed inline in
// PermitsCard/InstallSpecCard.

function bumpPermits() {
  const CRM = window.CRM;
  if (CRM) CRM.permits = (CRM.permits || []).slice();
}
function bumpMaterials() {
  const CRM = window.CRM;
  if (CRM) CRM.materials = (CRM.materials || []).slice();
}

// permits.status -> contact.stage forward map, exact mirror of
// PERMIT_STATUS_TO_STAGE (crm-right.jsx:3478-3482).
const PERMIT_STATUS_TO_STAGE = {
  submitted: 'permit_submit',
  waiting: 'permit_waiting',
  approved: 'permit_approved',
};

// Status badge color + label, exact mirror of PERMIT_PILL (crm-right.jsx:
// 3296-3302) mapped onto Ionic's stock IonBadge palette (this theme has not
// customized tertiary/success/warning/danger/medium, so 'primary', the
// navy brand color, stands in for the bespoke's blue 'waiting' pill; the
// other four map onto their obvious Ionic equivalents). Any status outside
// this map (including a manually-set 'rejected' row, which the bespoke's
// own PermitStatusActions never writes either) falls back to not_started's
// look, exact mirror of `PERMIT_PILL[status] || PERMIT_PILL.not_started`.
const PERMIT_STATUS_BADGE = {
  approved: { color: 'success', label: 'Approved' },
  submitted: { color: 'warning', label: 'Submitted' },
  waiting: { color: 'primary', label: 'Waiting' },
  blocked: { color: 'danger', label: 'Blocked' },
  not_started: { color: 'medium', label: 'Not started' },
};
export function permitStatusBadge(status) {
  return PERMIT_STATUS_BADGE[status] || PERMIT_STATUS_BADGE.not_started;
}

// Permit aging chip thresholds, exact mirror of PermitAgeChip (crm-right.jsx:
// 4256-4271): typical SC city turnaround is ~14 days, gold once past 7d
// submitted, red once past the 14d SLA. null once approved or never
// submitted (the chip has nothing to count).
export function permitAgeInfo(permit) {
  if (!permit || !permit.submitted_at || permit.status === 'approved') return null;
  const days = Math.floor((Date.now() - new Date(permit.submitted_at).getTime()) / 86400000);
  const SLA = 14;
  const overdue = days > SLA;
  const aging = days >= 7;
  return {
    days,
    color: overdue ? 'danger' : aging ? 'warning' : 'primary',
    label: overdue ? `Day ${days}, over SLA` : `Day ${days} of ${SLA}`,
  };
}

// Add a permit for a contact with none, exact mirror of PermitsCard.addPermit
// (crm-right.jsx:4107-4176): best-guess the jurisdiction from contact.
// jurisdiction against the shared BPP_JURISDICTIONS list (falls back to the
// first entry), resolves its jurisdiction_id best-effort (a failed lookup
// proceeds with a null FK rather than blocking, the jurisdiction_name still
// drives the UI), inserts a not_started row, then bumps the contact stage
// booked -> permit_submit (the bespoke's own rule: STARTING a permit IS that
// transition), with rollback on a failed stage write. Only ever fires the
// stage bump from 'booked' exactly like the bespoke, never a general
// forward-only bump (a permit added on a front-half or already-past-permit
// contact must not skip stages).
export async function addPermit(contact) {
  const CRM = window.CRM;
  if (!CRM || !CRM.__db || !contact) return { ok: false, error: 'no db/contact' };
  const list = window.BPP_JURISDICTIONS || [];
  const j = contact.jurisdiction
    ? (list.find(n => n.toLowerCase().includes(String(contact.jurisdiction).toLowerCase())) || list[0])
    : list[0];
  let jurisdictionId = null;
  try {
    const { data: jdata } = await CRM.__db.from('permit_jurisdictions').select('id').eq('name', j).limit(1);
    if (jdata && jdata[0] && jdata[0].id) jurisdictionId = jdata[0].id;
  } catch (_) { /* proceed with a null FK, mirrors the bespoke's own best-effort lookup */ }
  const { data, error } = await CRM.__db.from('permits').insert({
    contact_id: contact.id, jurisdiction_id: jurisdictionId, jurisdiction_name: j,
    status: 'not_started', permit_number: 'PENDING', cost_cents: 0,
  }).select().single();
  if (error) return { ok: false, error: error.message };
  const mapped = {
    id: data.id, contact_id: data.contact_id, jurisdiction_id: data.jurisdiction_id || null,
    jurisdiction: data.jurisdiction_name || j, jurisdiction_name: data.jurisdiction_name || j,
    permit_number: data.permit_number || 'PENDING', status: data.status || 'not_started',
    submitted_at: data.submitted_at || null, approved_at: data.approved_at || null,
    cost_cents: data.cost_cents || 0, blocker_note: data.blocker_note || null,
    created_at: data.created_at || new Date().toISOString(),
  };
  CRM.permits = [...(CRM.permits || []), mapped];
  window.dispatchEvent(new CustomEvent('crm-data-changed'));
  const contactId = contact.id;
  if (contact.stage === 'booked' && CRM.STAGE_STR_TO_NUM && CRM.STAGE_STR_TO_NUM.permit_submit != null) {
    const liveContact = () => (CRM.contacts || []).find(c => c.id === contactId) || contact;
    const cNow = liveContact();
    const previous = cNow.stage;
    cNow.stage = 'permit_submit';
    bumpContactsBeforeDispatch();
    const { error: stageErr } = await CRM.__db.from('contacts')
      .update({ stage: CRM.STAGE_STR_TO_NUM.permit_submit }).eq('id', contactId);
    if (stageErr) {
      liveContact().stage = previous;
      bumpContactsBeforeDispatch();
      return { ok: true, permit: mapped, stageError: stageErr.message };
    }
    if (typeof CRM.recordStageTransition === 'function') {
      CRM.recordStageTransition(contactId, CRM.STAGE_STR_TO_NUM[previous] ?? null, CRM.STAGE_STR_TO_NUM.permit_submit);
    }
  }
  return { ok: true, permit: mapped };
}

// Advance a permit's status, exact mirror of PermitStatusActions.advance
// (crm-right.jsx:3488-3532): optimistic mutate + persist the status and any
// stamps (submitted_at/approved_at/blocker_note), revert on error, then the
// FORWARD-ONLY stage sync (PERMIT_STATUS_TO_STAGE + STAGE_STR_TO_NUM compare,
// never drags the pipeline back, e.g. a later corrective "Mark waiting" must
// not undo an install). Re-resolves both the permit and the contact by id
// from the live CRM arrays before every mutation (not the closed-over
// argument), since a realtime refetch can replace either array wholesale
// while this await is in flight.
export async function advancePermitStatus(permit, contact, toStatus, stamps = {}) {
  const CRM = window.CRM;
  if (!CRM || !CRM.__db || !permit) return { ok: false, error: 'no db/permit' };
  const permitId = permit.id;
  const livePermit = () => (CRM.permits || []).find(p => p.id === permitId) || permit;
  const target = livePermit();
  const prev = {
    status: target.status, submitted_at: target.submitted_at,
    approved_at: target.approved_at, blocker_note: target.blocker_note,
  };
  target.status = toStatus;
  Object.assign(target, stamps);
  bumpPermits();
  window.dispatchEvent(new CustomEvent('crm-data-changed'));
  const patch = { status: toStatus, ...stamps };
  const { error } = await CRM.__db.from('permits').update(patch).eq('id', permitId);
  if (error) {
    Object.assign(livePermit(), prev);
    bumpPermits();
    window.dispatchEvent(new CustomEvent('crm-data-changed'));
    return { ok: false, error: error.message };
  }
  const targetStage = PERMIT_STATUS_TO_STAGE[toStatus];
  const contactId = contact && contact.id;
  if (contactId && targetStage && CRM.STAGE_STR_TO_NUM && CRM.STAGE_STR_TO_NUM[targetStage] != null) {
    const liveContact = () => (CRM.contacts || []).find(c => c.id === contactId) || contact;
    const cNow = liveContact();
    const targetNum = CRM.STAGE_STR_TO_NUM[targetStage];
    const currentNum = CRM.STAGE_STR_TO_NUM[cNow.stage] ?? 0;
    if (cNow.stage !== targetStage && targetNum > currentNum) {
      const previousStage = cNow.stage;
      cNow.stage = targetStage;
      bumpContactsBeforeDispatch();
      const { error: stageErr } = await CRM.__db.from('contacts').update({ stage: targetNum }).eq('id', contactId);
      if (stageErr) {
        liveContact().stage = previousStage;
        bumpContactsBeforeDispatch();
        return { ok: true, stageError: stageErr.message };
      }
      if (typeof CRM.recordStageTransition === 'function') {
        CRM.recordStageTransition(contactId, CRM.STAGE_STR_TO_NUM[previousStage] ?? null, targetNum);
      }
    }
  }
  return { ok: true };
}

// Freshly-computed local date, exact mirror of PermitStatusActions'
// freshToday / MaterialRow's advance (crm-right.jsx:3537, 4307-4308): the
// date is read at CLICK time inside the handler, never captured once at
// module load or render, so a tab left open past midnight can never stamp
// yesterday's date on a submitted_at/approved_at/ordered_at/etc field (the
// 2026-06-20 scar).
export function freshLocalDate() {
  const d = new Date();
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
}

// Re-jurisdiction a permit, exact mirror of JurisdictionEditor.pick
// (crm-right.jsx:3402-3430): optimistic flip of both jurisdiction fields,
// best-effort jurisdiction_id lookup by name (proceeds with a null FK on a
// failed lookup, same as addPermit above), revert on a failed persist.
export async function updatePermitJurisdiction(permit, contact, name) {
  const CRM = window.CRM;
  if (!CRM || !CRM.__db || !permit) return { ok: false, error: 'no db/permit' };
  if (permit.jurisdiction === name) return { ok: true, skipped: true };
  const permitId = permit.id;
  const livePermit = () => (CRM.permits || []).find(p => p.id === permitId) || permit;
  const target = livePermit();
  const prev = { jurisdiction: target.jurisdiction, jurisdiction_name: target.jurisdiction_name };
  target.jurisdiction = name;
  target.jurisdiction_name = name;
  bumpPermits();
  window.dispatchEvent(new CustomEvent('crm-data-changed'));
  let jurisdictionId = null;
  try {
    const { data } = await CRM.__db.from('permit_jurisdictions').select('id').eq('name', name).limit(1);
    if (data && data[0] && data[0].id) jurisdictionId = data[0].id;
  } catch (_) { /* proceed with a null FK */ }
  const { error } = await CRM.__db.from('permits')
    .update({ jurisdiction_name: name, jurisdiction_id: jurisdictionId }).eq('id', permitId);
  if (error) {
    const now_ = livePermit();
    now_.jurisdiction = prev.jurisdiction;
    now_.jurisdiction_name = prev.jurisdiction_name;
    bumpPermits();
    window.dispatchEvent(new CustomEvent('crm-data-changed'));
    return { ok: false, error: error.message };
  }
  livePermit().jurisdiction_id = jurisdictionId;
  bumpPermits();
  window.dispatchEvent(new CustomEvent('crm-data-changed'));
  return { ok: true };
}

// The 3 specialty kinds every install always has, exact mirror of
// InstallSpecCard's PERMANENT set (crm-right.jsx:4388) and the readiness
// gate's SPECIALTY list (crm-data.js:307). Never edit this list without
// checking both: a 4th entry here would render a part this UI can clear that
// the gate does not (or vice versa), the exact bug the 2026-07-02 fix closed.
export const MATERIAL_PERMANENT_KINDS = ['inlet', 'interlock', 'cord'];
const _PERMANENT_SET = new Set(MATERIAL_PERMANENT_KINDS);

// Extra (non-permanent) part kinds offered by the add-part picker, exact
// mirror of EXTRA_KINDS (crm-right.jsx:4492).
export const MATERIAL_EXTRA_KINDS = ['breaker', 'whip', 'surge', 'other'];

// Kind -> Title Case label, exact mirror of MAT_KIND_LABEL (crm-right.jsx:4286).
export function materialKindLabel(kind) {
  const k = String(kind || '');
  return k.charAt(0).toUpperCase() + k.slice(1);
}

// Status -> dot color + status word, exact mirror of MAT_STATUS
// (crm-right.jsx:4274-4279).
const MAT_STATUS_INFO = {
  not_ordered: { color: '#999', label: 'Not ordered' },
  ordered: { color: '#f59e0b', label: 'Ordered' },
  received: { color: '#2563eb', label: 'Received' },
  installed: { color: '#16a34a', label: 'Installed' },
};
export function materialStatusInfo(status) {
  return MAT_STATUS_INFO[status] || MAT_STATUS_INFO.not_ordered;
}

// Status -> the next-step action, exact mirror of MAT_NEXT (crm-right.jsx:
// 4280-4285). null at 'installed' (nothing further to advance to).
const MAT_NEXT = {
  not_ordered: { next: 'ordered', label: 'Mark ordered', stamp: 'ordered_at' },
  ordered: { next: 'received', label: 'Mark received', stamp: 'received_at' },
  received: { next: 'installed', label: 'Mark installed', stamp: 'installed_at' },
};
export function materialNextAction(status) {
  return MAT_NEXT[status] || null;
}

function mapMaterialRow(data) {
  return {
    id: data.id, contact_id: data.contact_id, kind: data.kind, status: data.status,
    ordered_at: data.ordered_at, received_at: data.received_at, installed_at: data.installed_at,
    created_at: data.created_at,
  };
}

// Ordering rows for the Install Spec card: the 3 permanent specialty kinds
// always render, synthesizing a client-side placeholder (never written to
// the DB until the first advance) when the contact has no row for that kind
// yet, exact mirror of InstallSpecCard's own row-build (crm-right.jsx:
// 4485-4489). Extras (any other kind) trail in whatever order they came
// back in.
export function buildMaterialRows(materials, contactId) {
  const mats = (materials || []).filter(m => m.contact_id === contactId);
  const byKind = kind => mats.find(m => m.kind === kind)
    || { kind, status: 'not_ordered', contact_id: contactId, _placeholder: true };
  const permanent = MATERIAL_PERMANENT_KINDS.map(byKind);
  const extras = mats.filter(m => !_PERMANENT_SET.has(m.kind));
  return [...permanent, ...extras];
}

// Advance one material row to its next status, exact mirror of MaterialRow.
// advance (crm-right.jsx:4298-4356): a placeholder row's first advance
// INSERTs (contact_id, kind, status, the ONE relevant stamp; the other two
// stamps explicitly null, matching the bespoke's own insert shape); an
// existing row UPDATEs in place, optimistic + revert on error, re-resolved
// by id after the await (a realtime refetch can replace CRM.materials
// wholesale while this is in flight).
export async function advanceMaterial(mat, contact) {
  const CRM = window.CRM;
  const next = MAT_NEXT[mat && mat.status];
  if (!next) return { ok: false, error: 'nothing to advance' };
  if (!CRM || !CRM.__db) return { ok: false, error: 'Supabase not loaded' };
  const stampDate = freshLocalDate();
  if (mat._placeholder) {
    const stamps = {
      ordered_at: next.stamp === 'ordered_at' ? stampDate : null,
      received_at: next.stamp === 'received_at' ? stampDate : null,
      installed_at: next.stamp === 'installed_at' ? stampDate : null,
    };
    const { data, error } = await CRM.__db.from('materials').insert({
      contact_id: contact.id, kind: mat.kind, status: next.next, ...stamps,
    }).select().single();
    if (error) return { ok: false, error: error.message };
    CRM.materials = [...(CRM.materials || []), mapMaterialRow(data)];
    window.dispatchEvent(new CustomEvent('crm-data-changed'));
    return { ok: true };
  }
  const matId = mat.id;
  const live = () => (CRM.materials || []).find(m => m.id === matId) || mat;
  const target = live();
  const prev = { status: target.status, [next.stamp]: target[next.stamp] };
  target.status = next.next;
  target[next.stamp] = stampDate;
  bumpMaterials();
  window.dispatchEvent(new CustomEvent('crm-data-changed'));
  const { error } = await CRM.__db.from('materials')
    .update({ status: next.next, [next.stamp]: stampDate }).eq('id', matId);
  if (error) {
    const now_ = live();
    now_.status = prev.status;
    now_[next.stamp] = prev[next.stamp];
    bumpMaterials();
    window.dispatchEvent(new CustomEvent('crm-data-changed'));
    return { ok: false, error: error.message };
  }
  return { ok: true };
}

// Reset a completed permanent row back to not_ordered, exact mirror of
// MaterialRow.reset (crm-right.jsx:4360-4384): the only escape hatch from an
// accidental "Mark installed", wipes all three date stamps. No-op on a
// placeholder (nothing to reset yet).
export async function resetMaterial(mat) {
  const CRM = window.CRM;
  if (!mat || mat._placeholder) return { ok: true, skipped: true };
  if (!CRM || !CRM.__db) return { ok: false, error: 'Supabase not loaded' };
  const matId = mat.id;
  const live = () => (CRM.materials || []).find(m => m.id === matId) || mat;
  const target = live();
  const prev = {
    status: target.status, ordered_at: target.ordered_at,
    received_at: target.received_at, installed_at: target.installed_at,
  };
  target.status = 'not_ordered';
  target.ordered_at = null; target.received_at = null; target.installed_at = null;
  bumpMaterials();
  window.dispatchEvent(new CustomEvent('crm-data-changed'));
  const { error } = await CRM.__db.from('materials')
    .update({ status: 'not_ordered', ordered_at: null, received_at: null, installed_at: null })
    .eq('id', matId);
  if (error) {
    Object.assign(live(), prev);
    bumpMaterials();
    window.dispatchEvent(new CustomEvent('crm-data-changed'));
    return { ok: false, error: error.message };
  }
  return { ok: true };
}

// Remove an EXTRA material row, exact mirror of MaterialRow.remove
// (crm-right.jsx:4390-4428): permanent kinds (inlet/interlock/cord) can
// never be removed (gated by the caller AND here, defense in depth). Returns
// the pre-delete snapshot so the caller's undo toast can re-insert via
// reinsertMaterial below; no confirm dialog, the 5s undo IS the safety net
// (deliberate asymmetry, do not add a confirm here).
export async function removeMaterial(mat) {
  const CRM = window.CRM;
  if (!CRM || !CRM.__db || !mat || _PERMANENT_SET.has(mat.kind)) return { ok: false, error: 'cannot remove this row' };
  const snap = { ...mat };
  const before = CRM.materials || [];
  const idx = before.findIndex(m => m.id === mat.id);
  if (idx >= 0) { const next = before.slice(); next.splice(idx, 1); CRM.materials = next; }
  window.dispatchEvent(new CustomEvent('crm-data-changed'));
  const { error } = await CRM.__db.from('materials').delete().eq('id', mat.id);
  if (error) {
    const cur = CRM.materials || [];
    if (!cur.some(m => m.id === mat.id)) CRM.materials = [...cur, snap];
    window.dispatchEvent(new CustomEvent('crm-data-changed'));
    return { ok: false, error: error.message };
  }
  return { ok: true, snap };
}

// Re-insert a removed extra, exact mirror of MaterialRow.remove's own undo
// handler (crm-right.jsx:4406-4425): strips id/created_at/updated_at from the
// snapshot so the insert mints a fresh row (never re-uses the deleted id).
// Called from the undo toast's button handler (ionic-app.jsx), which must
// use toastController rather than a component-scoped useIonToast instance,
// since the material's owning row may have scrolled out or the page
// navigated away well inside the 5s window.
export async function reinsertMaterial(snap) {
  const CRM = window.CRM;
  if (!CRM || !CRM.__db || !snap) return { ok: false, error: 'no db/material' };
  const { id, created_at, updated_at, ...rest } = snap;
  const { data, error } = await CRM.__db.from('materials').insert(rest).select().single();
  if (error) return { ok: false, error: error.message };
  CRM.materials = [...(CRM.materials || []), mapMaterialRow(data)];
  window.dispatchEvent(new CustomEvent('crm-data-changed'));
  return { ok: true };
}

// Add an extra (non-permanent) material row, exact mirror of
// InstallSpecCard.addExtra (crm-right.jsx:4494-4521): plain insert, always
// not_ordered, no stamps.
export async function addExtraMaterial(contact, kind) {
  const CRM = window.CRM;
  if (!CRM || !CRM.__db || !contact) return { ok: false, error: 'Supabase not loaded' };
  const { data, error } = await CRM.__db.from('materials')
    .insert({ contact_id: contact.id, kind, status: 'not_ordered' }).select().single();
  if (error) return { ok: false, error: error.message };
  CRM.materials = [...(CRM.materials || []), mapMaterialRow(data)];
  window.dispatchEvent(new CustomEvent('crm-data-changed'));
  return { ok: true };
}

// ── Job photos (Increment S2) ────────────────────────────────────────────
// URL allowlist, exact mirror of PhotosSection's own isTrustedMediaUrl
// (crm-right.jsx:2234-2246): parse the URL and check the actual hostname
// rather than a regex (a regex can be bypassed by
// https://attacker.com/.twilio.com/x.png since `.*` does not anchor at a
// host boundary). Job photos only ever come from the message-media bucket
// via crm-media-upload, so this always passes for a real row, it is a
// defense-in-depth filter against a corrupted/foreign URL slipping in.
export function isTrustedJobPhotoUrl(raw) {
  if (!raw || typeof raw !== 'string') return false;
  try {
    const u = new URL(raw);
    if (u.protocol !== 'https:') return false;
    const h = u.hostname.toLowerCase();
    return h === 'api.twilio.com' || h.endsWith('.twilio.com') || h.endsWith('.supabase.co');
  } catch (_) { return false; }
}

// Client-side cap, exact mirror of PhotosSection's own 10 MB/file guard
// (crm-right.jsx:2353). The crm-media-upload edge fn backstops at 15 MB;
// this is the honest "too large" toast BEFORE any network call.
export const JOB_PHOTO_MAX_BYTES = 10 * 1024 * 1024;

// Re-entrancy lock, module-level Set keyed by contact.id (same STRONGER
// Path A pattern as _stageAdvanceLocks above): a fast double-tap on "Add
// photo" while a multi-file upload loop is mid-flight must not start a
// second overlapping loop.
const _jobPhotoUploadLocks = new Set();
export function claimJobPhotoUpload(contactId) {
  if (_jobPhotoUploadLocks.has(contactId)) return false;
  _jobPhotoUploadLocks.add(contactId);
  return true;
}
export function releaseJobPhotoUpload(contactId) {
  _jobPhotoUploadLocks.delete(contactId);
}

// Upload ONE job photo through the crm-media-upload edge fn (service-role
// write; DECIDED CALL, never storage.from().upload() directly, the bucket
// grants INSERT to authenticated/service_role only and the CRM only ever
// holds the anon/publishable key) then insert its job_photos row, mirroring
// PhotosSection.onFileChange's per-file insert shape exactly (crm-right.jsx:
// 2372-2377): contact_id, url, storage_path, uploaded_by:'key',
// photo_kind:'other'. Optimistic push + ref bump BEFORE dispatch (scar: ref
// bumps before crm-data-changed). Caller loops this sequentially over a
// multi-file pick and owns the ok/fail summary toast, exact mirror of the
// bespoke's own per-file try/catch-and-count loop.
export async function uploadJobPhoto(file, contact) {
  const CRM = window.CRM;
  if (!CRM || typeof CRM.__invokeFn !== 'function' || !CRM.__db) return { ok: false, error: 'Supabase not loaded' };
  if (!contact || !file) return { ok: false, error: 'no contact/file' };
  if (!file.type || !file.type.startsWith('image/')) return { ok: false, error: 'Only image files' };
  if (file.size > JOB_PHOTO_MAX_BYTES) return { ok: false, error: `"${file.name}" is too large (10 MB max)` };
  let dataBase64;
  try {
    dataBase64 = await new Promise((resolve, reject) => {
      const r = new FileReader();
      r.onload = () => { const s = String(r.result || ''); resolve(s.slice(s.indexOf(',') + 1)); };
      r.onerror = () => reject(new Error('could not read file'));
      r.readAsDataURL(file);
    });
  } catch (e) {
    return { ok: false, error: (e && e.message) || 'could not read file' };
  }
  const { data, error } = await CRM.__invokeFn('crm-media-upload', {
    body: { contactId: contact.id, contentType: file.type, dataBase64, scope: 'job-photo', filename: file.name },
  });
  if (error || !data || data.ok === false || !data.url) {
    let detail = (data && data.error) || (error && error.message) || 'upload failed';
    try {
      const eb = error && error.context ? await error.context.json() : null;
      if (eb && eb.error) detail = eb.error;
    } catch (_) { /* no parseable error body */ }
    return { ok: false, error: detail };
  }
  const { data: row, error: insErr } = await CRM.__db.from('job_photos').insert({
    contact_id: contact.id, url: data.url, storage_path: data.path,
    uploaded_by: 'key', photo_kind: 'other',
  }).select().single();
  if (insErr) return { ok: false, error: insErr.message };
  const mapped = {
    id: row.id, contact_id: row.contact_id, url: row.url, storage_path: row.storage_path,
    uploaded_at: row.uploaded_at, uploaded_by: row.uploaded_by || 'key',
    annotated: !!row.annotated, photo_kind: row.photo_kind || 'other',
  };
  CRM.jobPhotos = [...(CRM.jobPhotos || []), mapped];
  window.dispatchEvent(new CustomEvent('crm-data-changed', { detail: { table: 'job_photos' } }));
  return { ok: true, photo: mapped };
}

// Remove a job photo, DB row only. DEVIATION (decided call, banked, not a
// gap I introduced silently): the bespoke's own removeJobPhoto also does a
// best-effort storage.from('message-media').remove([path]) blob delete
// (crm-right.jsx:2409-2416); that is deliberately NOT ported here, the
// CRM's anon/publishable key has no delete grant on the bucket (the same
// hardening that forced uploads through the edge fn in the first place) and
// there is no "crm-media-delete" edge fn yet. The orphaned storage object
// joins the existing orphan-cleanup backlog item. Caller owns the
// confirm-first "this cannot be undone" dialog; this only ever runs after
// that confirm resolves true.
export async function removeJobPhoto(photo, contact) {
  const CRM = window.CRM;
  if (!CRM || !CRM.__db || !photo) return { ok: false, error: 'no db/photo' };
  const before = CRM.jobPhotos || [];
  const idx = before.findIndex(p => p.id === photo.id);
  const snap = idx >= 0 ? before[idx] : photo;
  if (idx >= 0) {
    const next = before.slice();
    next.splice(idx, 1);
    CRM.jobPhotos = next;
    window.dispatchEvent(new CustomEvent('crm-data-changed', { detail: { table: 'job_photos' } }));
  }
  const { error } = await CRM.__db.from('job_photos').delete().eq('id', photo.id);
  if (error) {
    const cur = CRM.jobPhotos || [];
    if (!cur.some(p => p.id === photo.id)) CRM.jobPhotos = [...cur, snap];
    window.dispatchEvent(new CustomEvent('crm-data-changed', { detail: { table: 'job_photos' } }));
    return { ok: false, error: error.message };
  }
  return { ok: true };
}

// ── POM 20-point panel inspection (Increment S2) ─────────────────────────
// Key sells the $447 Peace of Mind manual. Every install includes a 20-point
// panel safety inspection; this is where Key RECORDS it (Pass/Fail/N/A + an
// optional note per point + the date), and one tap generates the customer's
// POM PDF with the real results filled in. Gated to POM-paid contacts only
// (a proposal with pom_accepted === true and not superseded), per Key
// 2026-06-05. Labels + order are an EXACT mirror of POM_POINTS (crm-right.jsx:
// 579-600), the insp string maps 1:1 to the customer PDF's grid, do not
// reorder or reword without checking the PDF too.
export const POM_POINTS = [
  'Panel is easily accessible',
  'Panel doors open and close easily',
  'Free from corrosion or damage',
  'Breakers clearly labeled',
  'Cable sheathing properly removed',
  'Breakers match the panel',
  'All breaker spaces properly filled',
  'Free from overcrowding',
  'All knockouts, bushings, screws present',
  'Wires properly colored or marked',
  'Neutral wires properly installed',
  'Proper grounding inside the panel',
  'Smoke alarms under 10 years and working',
  'One wire per lug on each breaker',
  'GFCI/AFCI breakers trip properly',
  'No signs of overheating',
  'Wire in good condition',
  'Main breaker functioning properly',
  'Breakers output correct voltage',
  'Wires secure to breakers and lugs',
];

// Find the POM-paid proposal for a contact's proposal list + its amp spec,
// exact mirror of POMInspectionButton's own gate + amp derivation
// (crm-right.jsx:751-752).
export function findPomProposal(proposals) {
  return (proposals || []).find(p => p.pom_accepted && !p.superseded_at) || null;
}
export function pomAmpFor(pomProposal) {
  if (!pomProposal) return '30';
  return String(pomProposal.amp_spec || pomProposal.amp_type || '30').indexOf('50') >= 0 ? '50' : '30';
}

// Existing-inspection resolver, exact mirror of POMInspectionButton's own
// read (crm-right.jsx:753-758): prefer whichever of the DB copy and the
// on-device localStorage fallback has the newer saved_at (a newer local
// copy means the original DB write failed and is still pending retry).
export function resolvePomExisting(contact) {
  let local = null;
  try { local = JSON.parse(localStorage.getItem('bpp_pom_insp_' + contact.id) || 'null'); } catch (_) { local = null; }
  const dbExisting = (contact && contact.pom_inspection) || null;
  const localIsNewer = !!(local && (!dbExisting || String(local.saved_at || '') > String(dbExisting.saved_at || '')));
  return { existing: localIsNewer ? local : dbExisting, localIsNewer, local };
}

// Retry a locally-fallback-saved inspection into the DB, exact mirror of
// POMInspectionButton's own once-per-mount retry effect (crm-right.jsx:
// 760-768). Best-effort; a second failure just leaves the local copy in
// place for the next mount to retry again.
export async function retryPomSync(contact, local) {
  const CRM = window.CRM;
  if (!CRM || !CRM.__db || !local || !contact) return { ok: false };
  const { error } = await CRM.__db.from('contacts').update({ pom_inspection: local }).eq('id', contact.id);
  if (error) return { ok: false, error: error.message };
  const live = (CRM.contacts || []).find(c => c.id === contact.id) || contact;
  live.pom_inspection = local;
  bumpContactsBeforeDispatch();
  try { localStorage.removeItem('bpp_pom_insp_' + contact.id); } catch (_) { /* best-effort */ }
  return { ok: true };
}

// Re-entrancy lock (module-level Set), same pattern as _stageAdvanceLocks.
const _pomSaveLocks = new Set();

// Save (or Save+Generate) an inspection, exact mirror of persist()
// (crm-right.jsx:646-665): DB write first; on success clear the on-device
// fallback (DB is now the source of truth, a stale local copy must never
// shadow it again); on failure, write the on-device fallback so the next
// mount's retry effect picks it up. Returns 'db' | 'local' | false exactly
// like the bespoke's own persist() return contract ('inflight' added here
// for the re-entrancy guard, a state the bespoke's single-flight button
// disable already prevented by other means).
export async function savePomInspection(contact, payload) {
  const CRM = window.CRM;
  if (!contact) return false;
  if (_pomSaveLocks.has(contact.id)) return 'inflight';
  _pomSaveLocks.add(contact.id);
  try {
    let dbOk = false;
    if (CRM && CRM.__db) {
      const { error } = await CRM.__db.from('contacts').update({ pom_inspection: payload }).eq('id', contact.id);
      if (!error) {
        dbOk = true;
        const live = (CRM.contacts || []).find(c => c.id === contact.id) || contact;
        live.pom_inspection = payload;
        bumpContactsBeforeDispatch();
      }
    }
    if (dbOk) {
      try { localStorage.removeItem('bpp_pom_insp_' + contact.id); } catch (_) { /* best-effort */ }
      return 'db';
    }
    try { localStorage.setItem('bpp_pom_insp_' + contact.id, JSON.stringify(payload)); return 'local'; }
    catch (_) { return false; }
  } finally {
    _pomSaveLocks.delete(contact.id);
  }
}

// The PDF URL, exact mirror of pdfUrl's construction (crm-right.jsx:641-644).
// results/idate/sys ONLY. The notes NEVER leave the DB, they must never be
// added to this URL (scar-critical, the PDF is a public link a customer can
// receive).
export function pomPdfUrl(contact, amp, results, idate, sys) {
  const insp = results.join('');
  const name = ((contact && contact.name) || '').trim() || 'Customer';
  const sysParams = [['panel_loc', sys.panel], ['inlet_loc', sys.inlet], ['gen', sys.gen], ['interlock', sys.interlock], ['circuits', sys.circuits]]
    .filter(pair => (pair[1] || '').trim())
    .map(pair => '&' + pair[0] + '=' + encodeURIComponent(pair[1].trim()))
    .join('');
  return `/pom-guide/index.html?amp=${amp}&name=${encodeURIComponent(name)}&insp=${insp}&idate=${encodeURIComponent(idate)}` + sysParams;
}
