      // send-sms persists server-side (supabase/functions/send-sms/
      // index.ts:352-355), so ThreadRow's existing stripMediaTokens contract
      // renders this bubble identically before and after the realtime
      // refetch, zero new render logic needed.
      const bubbleBody = mediaUrls.length
        ? mediaUrls.map(u => '[media:' + u + ']').join(' ') + (finalBody ? ' ' + finalBody : '')
        : finalBody;
