      const saved = result.message;
      if (saved && saved.id != null && stillHere()) {
        setLocalMsgs(ms => ms.map(x => x.id === tempId
          ? { ...x, serverId: saved.id, sent_at: saved.created_at || saved.sent_at || x.sent_at }
          : x));
      }
